/**
 * Available discount coupons. Codes are checked case-insensitively.
 * - type 'percent': discount is subtracted as a percentage of totalPrice.
 * - type 'fixed': a flat amount is subtracted (capped at totalPrice).
 *
 * @type {Record<string, { code: string, label: string, type: 'percent' | 'fixed', value: number }>}
 */
export const COUPONS = {
  DESCUENTO10: { code: 'DESCUENTO10', label: '10 % de descuento', type: 'percent', value: 10 },
  OFERTA20: { code: 'OFERTA20', label: '20 % de descuento', type: 'percent', value: 20 },
  REBAJAS30: { code: 'REBAJAS30', label: '30 % de descuento', type: 'percent', value: 30 },
  VERANO15: { code: 'VERANO15', label: '15 % de descuento', type: 'percent', value: 15 },
  PROMO5: { code: 'PROMO5', label: '$5 de descuento', type: 'fixed', value: 5 },
  AHORRA10: { code: 'AHORRA10', label: '$10 de descuento', type: 'fixed', value: 10 },
  AHORRA15: { code: 'AHORRA15', label: '$15 de descuento', type: 'fixed', value: 15 },
  BIENVENIDA: { code: 'BIENVENIDA', label: '25 % de descuento por primera compra', type: 'percent', value: 25 },
  SUPERAHORRO: { code: 'SUPERAHORRO', label: '40 % de descuento', type: 'percent', value: 40 },
};

/**
 * Validates a raw coupon code and returns the coupon object or null.
 * @param {string} rawCode
 * @returns {{ code: string, label: string, type: 'percent' | 'fixed', value: number } | null}
 */
export function findCoupon(rawCode) {
  const normalized = rawCode.trim().toUpperCase();
  return COUPONS[normalized] ?? null;
}

/**
 * Calculates the discount amount for a given coupon and subtotal.
 * @param {{ type: 'percent' | 'fixed', value: number } | null} coupon
 * @param {number} subtotal
 * @returns {number}
 */
export function calcDiscount(coupon, subtotal) {
  if (!coupon || subtotal <= 0) return 0;
  if (coupon.type === 'percent') {
    return Math.min((subtotal * coupon.value) / 100, subtotal);
  }
  return Math.min(coupon.value, subtotal);
}
